static uint8_t
rrc_M2AP_select_MCS_from_CQI(uint8_t Mod_id, uint8_t sync_area, uint8_t requested_mcs) {
  eNB_RRC_INST *rrc = RC.rrc[Mod_id];
  uint8_t adjusted_mcs = requested_mcs;

  // If we have CQI information available, use it to adjust MCS
  if (rrc && rrc->carrier[0].num_UEs > 0) {
    // Find the UE with the worst CQI in this sync area to ensure all UEs can decode
    uint8_t min_cqi = 15; // Start with best possible CQI
    int ue_id;

    for (ue_id = 0; ue_id < MAX_MOBILES_PER_ENB; ue_id++) {
      if (rrc->ue_context[ue_id] && rrc->ue_context[ue_id]->ue_context.UE_Capability) {
        // Check if UE is part of this MBSFN sync area (simplified check)
        // In real implementation, this would check UE's MBMS interest

        // Use MAC layer CQI information if available
        if (RC.mac[Mod_id] && RC.mac[Mod_id]->UE_list.num_UEs > 0) {
          int mac_ue_id = find_UE_id(Mod_id, rrc->ue_context[ue_id]->ue_context.rnti);
          if (mac_ue_id >= 0) {
            uint8_t cqi = RC.mac[Mod_id]->UE_list.UE_sched_ctrl[mac_ue_id].dl_cqi[0];
            if (cqi < min_cqi) {
              min_cqi = cqi;
            }
          }
        }
      }
    }

    // If we found valid CQI values, adjust MCS accordingly
    if (min_cqi < 15) {
      uint8_t max_mcs_from_cqi = cqi_to_mcs[min_cqi];

      // Use the more conservative MCS (lower value)
      adjusted_mcs = (requested_mcs < max_mcs_from_cqi) ? requested_mcs : max_mcs_from_cqi;

      LOG_I(RRC, "MBMS MCS selection: requested MCS %d, min CQI %d -> max MCS %d, selected MCS %d\n",
            requested_mcs, min_cqi, max_mcs_from_cqi, adjusted_mcs);
    }
  }

  // Ensure MCS is within valid range for MBMS (0-28 for LTE)
  if (adjusted_mcs > 28) {
    adjusted_mcs = 28;
  }

  return adjusted_mcs;
}

